#include <bits/stdc++.h>
using namespace std;
struct Number{
    int p,q;
}a,b;
int gcd(int x,int y){
	x=abs(x),y=abs(y);
	if(x<y)
		swap(x,y);
	return (y==0?x:gcd(y,x%y));
}
Number Add(Number x,Number y){
    int lcm=x.q*y.q/gcd(x.q,y.q);
    Number ans={x.p*(lcm/x.q)+y.p*(lcm/y.q),lcm};
    return {ans.p/gcd(ans.p,ans.q),ans.q/gcd(ans.p,ans.q)};
}
Number Minus(Number x,Number y){
    int lcm=x.q*y.q/gcd(x.q,y.q);
    Number ans={x.p*(lcm/x.q)-y.p*(lcm/y.q),lcm};
    return {ans.p/gcd(ans.p,ans.q),ans.q/gcd(ans.p,ans.q)};
}
void output(Number x){
	if(x.q==1)
        printf("%d\n",x.p);
    else
        printf("%d/%d\n",x.p,x.q);
}
int main(){
    a={0,1};
    int num=0,c=1,w=0;
    string s;
    cin>>s;
    //output(Add({0,1},{1,2}));
    for(int i=0;i<s.size();i++){
        if(s[i]>='0' && s[i]<='9')
            num=num*10+s[i]-'0';
        else if(s[i]=='/')
            b.p=num,num=0;
        else if(i>0){
            b.q=num,num=0;
            //printf("%d %d/%d\n",w,b.p,b.q);
            if(w==0)
                a=Add(a,b);
            else
                a=Minus(a,b);
            
            w=(s[i]=='-');
        }else
        	w=1;
    }
    b.q=num,num=0;
    if(w==0)
        a=Add(a,b);
    else
        a=Minus(a,b);
    output(a);
    return 0;
}
